mapper.sql:
/* wms-inbound-asrtwork-sql-oracle.xml - selectAsrtWksql - 아소트 입고 정보 SQL */ SELECT '0' AS CHK , CTKEY , CTNM , OWKEY , OWNM , IBHDKEY , IBDTKEY , IBEXPCTDATE , ICKEY , ICNM , EXPCTQTY_UNIT , IBQTY_UNIT , EXPCTQTY , IBQTY , ASRTWKTGTYN , ASRTWKCOMPLYN , ASRTWKQTY , UPRIBDTKEY , INSERTDATE , INSERTURKEY , UPDATEDATE , UPDATEURKEY FROM ( SELECT A.CTKEY , D.CTNM , A.OWKEY , C.OWNM , A.IBHDKEY , B.IBDTKEY , A.IBEXPCTDATE , CASE WHEN B.EXPCTQTY > 0 THEN ROUND(B.EXPCTQTY / COALESCE(G.ICUNITQTY, 1),2) ELSE B.EXPCTQTY END AS EXPCTQTY_UNIT , CASE WHEN B.IBQTY > 0 THEN ROUND(B.IBQTY / COALESCE(G.ICUNITQTY, 1),2) ELSE B.IBQTY END AS IBQTY_UNIT , B.EXPCTQTY , B.IBQTY , A.IBHDTYPECD , A.IBSTATUSCD , B.ICKEY , E.ICNM , B.ASRTWKTGTYN , COALESCE(B.ASRTWKCOMPLYN, 'N') AS ASRTWKCOMPLYN , B.ASRTWKQTY , B.UPRIBDTKEY , A.INSERTDATE , A.INSERTURKEY , A.UPDATEDATE , A.UPDATEURKEY FROM TWORK_INFO_IB_HD A INNER JOIN TWORK_INFO_IB_DT B ON A.CTKEY = B.CTKEY AND A.IBHDKEY = B.IBHDKEY INNER JOIN TWORK_MST_OW C ON B.OWKEY = C.OWKEY INNER JOIN TWORK_MST_CT D ON A.CTKEY = D.CTKEY INNER JOIN TWORK_MST_IC E ON A.CTKEY = E.CTKEY AND A.OWKEY = E.OWKEY AND B.ICKEY = E.ICKEY LEFT OUTER JOIN TWORK_MST_ICUTXTYPE G ON B.CTKEY = G.CTKEY AND B.OWKEY = G.OWKEY AND B.ICKEY = G.ICKEY AND B.UOM = G.ICUNITTYPECD ) A WHERE A.IBSTATUSCD != '99' AND A.ASRTWKTGTYN = 'Y' AND A.UPRIBDTKEY IS NULL AND A.IBQTY > 0 AND A.CTKEY = COALESCE(#{CTKEY}, #{sctkey}) AND A.OWKEY = COALESCE(#{OWKEY}, #{sowkey})
AND A.IBEXPCTDATE BETWEEN #{IBEXPCTDATE_FROM} AND #{IBEXPCTDATE_TO}
AND EXISTS ( SELECT 1 FROM TWORK_MST_ICBARCODE X WHERE X.CTKEY = A.CTKEY AND X.OWKEY = A.OWKEY AND X.ICKEY = A.ICKEY AND X.USEYN = 'Y' AND X.BARCODE = #{BARCODE} )
AND A.ICNM LIKE '%'|| #{ICNM} ||'%'
AND A.ASRTWKCOMPLYN = #{ASRTWKCOMPLYN}
#{ickey}

