mapper.update:
/* wms-inbound-asrtWk-sql-oracle.xml - updateIbDtIbqty - 아소트 작업 수량   */
UPDATE TWORK_INFO_IB_DT
   SET ASRTWKQTY 	 = ASRTWKQTY + #{asrtwkqty}
	 , ASRTWKCOMPLYN = (
						SELECT CASE WHEN IBQTY = SUM(ASRTWKQTY) + #{asrtwkqty} THEN 'Y'
									ELSE 'N' END
						  FROM TWORK_INFO_IB_DT
						 WHERE IBHDKEY = #{ibhdkey}
						   AND IBDTKEY = #{ibdtkey}
						 GROUP BY CTKEY, OWKEY, IBHDKEY, IBDTKEY, IBQTY
						)
 WHERE CTKEY 		= #{ctkey}
   AND OWKEY 		= #{owkey}
   AND IBHDKEY 		= #{ibhdkey}
   AND IBDTKEY 		= #{ibdtkey}

mapper.select:
/* wms-inbound-asrtWk-sql-oracle.xml - selectIbdtAsrtCntCheck - 입고 상세 아소트 상품 생성내역 조회 */
SELECT COUNT(*)
  FROM TWORK_INFO_IB_DT
 WHERE CTKEY 		= #{ctkey}
   AND OWKEY 		= #{owkey}
   AND IBHDKEY 		= #{ibhdkey}
   AND UPRIBDTKEY	= #{ibdtkey}
   AND ICKEY 		= #{ickey}

/* wms-inbound-asrtWk-sql-oracle.xml - selectAsrtWorkMstIc - 상품 마스터 조회  */
SELECT A.*
	 , B.WEIGHT
	 , COALESCE(B.ICUNITQTY, 1) AS ICUNITQTY
  FROM TWORK_MST_IC A
  LEFT OUTER JOIN TWORK_MST_ICUTXTYPE B
	ON A.CTKEY = B.CTKEY
   AND A.OWKEY = B.OWKEY
   AND A.ICKEY = B.ICKEY
   AND B.ICUNITTYPECD = COALESCE(#{icunittypecd}, 'INN')
 WHERE A.CTKEY 		= #{ctkey}
   AND A.OWKEY 		= #{owkey}
   AND A.ICKEY 		= #{ickey}

mapper.insert:
/* wms-inbound-asrtWk-sql-oracle.xml - insertAsrtdticIbdt - 아소트 자상품 입고 상세 생성  */
 INSERT INTO TWORK_INFO_IB_DT
	  ( CTKEY
	  , OWKEY
	  , IBHDKEY
	  , IBDTKEY
	  , UPRIBDTKEY
	  , ICKEY
	  , SBKEY
	  , ICUNITKEY
	  , INITQTY
	  , EXPCTQTY
	  , IBQTY
	  , CNFRMQTY
	  , DMGQTY
	  , RJQTY
	  , UOM
	  , CPAMT
	  , PRDCTDATE
	  , EXPDATE
	  , ORHDKEY
	  , ORDTKEY
	  , EXTORDERKEY
	  , EXPORDERLINENO
	  , SLPRCAMT
	  , IBNISRSNCD
	  , IBNISDTRSNCONT
	  , ORGCHITNO
	  , ORGCHITSEQNO
	  , ORGCHITDATE
	  , ACKEY
	  , ICTMPRDIVCD
	  , DCKEY
	  , ILBHSKEY
	  , IBCNFRMPRCSDATE
	  , IBCNFRMURKEY
	  , IBDDLNDATE
	  , IBDDLNURKEY
	  , UPDATEKEY
	  , WKCHNLCD
	  , IBDTSTATUSCD
	  , WEIGHT
	  , ASRTMASICKEY
	  , ASRTWKTGTYN
	  , ASRTWKCOMPLYN
	  , ASRTWKQTY
	  , PLCMSTATUSCD
	  , INSERTDATE
	  , INSERTURKEY
	  , UPDATEDATE
	  , UPDATEURKEY
	  ) VALUES
	  ( #{ctkey}
	  , #{owkey}
	  , #{ibhdkey}
	  , (
		 SELECT COALESCE (
				(
					SELECT MAX(IBDTKEY::INTEGER) + 1 AS UPRIBDTKEY
					  FROM TWORK_INFO_IB_DT
					 WHERE IBHDKEY = #{ibhdkey}
					   AND UPRIBDTKEY = #{ibdtkey}
				) ,
				(
					SELECT MAX(IBDTKEY::INTEGER) + 1 AS UPRIBDTKEY
					  FROM TWORK_INFO_IB_DT
					 WHERE IBHDKEY = #{ibhdkey}
					  AND IBDTKEY = #{ibdtkey}
				)
			)
		)
	  , #{upribdtkey}
	  , #{ickey}
	  , #{sbkey}
	  , #{icunitkey}
	  , #{initqty}
	  , #{expctqty}
	  , #{ibqty}
	  , #{cnfrmqty}
	  , #{dmgqty}
	  , #{rjqty}
	  , #{uom}
	  , #{cpamt}
	  , #{prdctdate}
	  , #{expdate}
	  , #{orhdkey}
	  , #{ordtkey}
	  , #{extorderkey}
	  , #{exporderlineno}
	  , #{slprcamt}
	  , #{ibnisrsncd}
	  , #{ibnisdtrsncont}
	  , #{orgchitno}
	  , #{orgchitseqno}
	  , #{orgchitdate}
	  , #{ackey}
	  , #{ictmprdivcd}
	  , #{dckey}
	  , #{ilbhskey}
	  , #{ibcnfrmprcsdate}
	  , #{ibcnfrmurkey}
	  , #{ibddlndate}
	  , #{ibddlnurkey}
	  , #{updatekey}
	  , #{wkchnlcd}
	  , #{ibdtstatuscd}
	  , #{weight}
	  , #{asrtmasickey}
	  , #{asrtwktgtyn}
	  , #{asrtwkcomplyn}
	  , #{asrtwkqty}
	  , #{plcmstatuscd}
	  , #{sysdate}
	  , #{surkey}
	  , #{sysdate}
	  , #{surkey}
	  )

mapper.select:
/* wms-inbound-asrtWk-sql-oracle.xml - selectIbdtByUpribdtkeyAndIckey - 입고 상세 조회 */
SELECT *
  FROM TWORK_INFO_IB_DT
 WHERE CTKEY 		= #{ctkey}
   AND OWKEY 		= #{owkey}
   AND IBHDKEY 		= #{ibhdkey}
   AND UPRIBDTKEY	= #{upribdtkey}

	AND ICKEY 		= #{ickey}

mapper.update:
/* wms-inbound-asrtWk-sql-oracle.xml - updateIbDtAsrtdt - 입고 상세 아소트 자상품 수량 수정 */
UPDATE TWORK_INFO_IB_DT
   SET INITQTY  	= INITQTY 	+ 	#{asrtwkqty}
	 , EXPCTQTY 	= EXPCTQTY 	+ 	#{asrtwkqty}
	 , IBQTY  		= IBQTY 	+ 	#{asrtwkqty}
	 , IBDTSTATUSCD	= #{ibdtstatus}
 WHERE CTKEY 		= #{ctkey}
   AND OWKEY 		= #{owkey}
   AND IBHDKEY 		= #{ibhdkey}
   AND IBDTKEY 		= #{ibdtkey}

mapper.delete:
/* wms-inbound-asrtWk-sql-oracle.xml - deleteIbdtArtdtickey - 입고 상세 아소트 자상품 삭제 */
